   }

+  // If both compares have the same predicate and share a common operand,
+  // and the other operands are constants, we may be able to fold.
+  if (PredL == PredR) {
+    // Determine which operand is the shared non-constant value and which are
+    // the constants.
+    const APFloat *C0, *C1;
+    bool LHS_ConstIsRHS, RHS_ConstIsRHS;
+    if (LHS0 == RHS0) {
+      // Both have the value on the left, constants on the right.
+      if (!match(LHS1, m_APFloat(C0)) || !match(RHS1, m_APFloat(C1)))
+        return nullptr;
+      LHS_ConstIsRHS = true;
+      RHS_ConstIsRHS = true;
+    } else if (LHS1 == RHS1) {
+      // Both have the value on the right, constants on the left.
+      if (!match(LHS0, m_APFloat(C0)) || !match(RHS0, m_APFloat(C1)))
+        return nullptr;
+      LHS_ConstIsRHS = false;
+      RHS_ConstIsRHS = false;
+    } else if (LHS0 == RHS1) {
+      // LHS has value on left (constant on right), RHS has value on right (constant on left).
+      if (!match(LHS1, m_APFloat(C0)) || !match(RHS0, m_APFloat(C1)))
+        return nullptr;
+      LHS_ConstIsRHS = true;
+      RHS_ConstIsRHS = false;
+    } else if (LHS1 == RHS0) {
+      // LHS has value on right (constant on left), RHS has value on left (constant on right).
+      if (!match(LHS0, m_APFloat(C0)) || !match(RHS1, m_APFloat(C1)))
+        return nullptr;
+      LHS_ConstIsRHS = false;
+      RHS_ConstIsRHS = true;
+    } else {
+      return nullptr;
+    }
+
+    // Compare the two constants to determine which set is a superset of the other.
+    auto CompareResult = C0->compare(*C1);
+    bool C0ContainsC1; // Does the set for C0 contain the set for C1?
+    switch (PredL) {
+    default:
+      return nullptr;
+    case FCmpInst::FCMP_OLT:
+    case FCmpInst::FCMP_ULT:
+      // For x < C: larger constant => larger set.
+      // C0's set contains C1's set if C0 >= C1.
+      C0ContainsC1 = CompareResult == APFloat::cmpGreaterThan ||
+                     CompareResult == APFloat::cmpEqual;
+      break;
+    case FCmpInst::FCMP_OLE:
+    case FCmpInst::FCMP_ULE:
+      // For x <= C: larger constant => larger set.
+      // C0's set contains C1's set if C0 >= C1.
+      C0ContainsC1 = CompareResult == APFloat::cmpGreaterThan ||
+                     CompareResult == APFloat::cmpEqual;
+      break;
+    case FCmpInst::FCMP_OGT:
+    case FCmpInst::FCMP_UGT:
+      // For x > C: smaller constant => larger set.
+      // C0's set contains C1's set if C0 <= C1.
+      C0ContainsC1 = CompareResult == APFloat::cmpLessThan ||
+                     CompareResult == APFloat::cmpEqual;
+      break;
+    case FCmpInst::FCMP_OGE:
+    case FCmpInst::FCMP_UGE:
+      // For x >= C: smaller constant => larger set.
+      // C0's set contains C1's set if C0 <= C1.
+      C0ContainsC1 = CompareResult == APFloat::cmpLessThan ||
+                     CompareResult == APFloat::cmpEqual;
+      break;
+    }
+
+    if (CompareResult == APFloat::cmpEqual) {
+      // Both compares are identical; just pick one.
+      return static_cast<Value *>(LHS);
+    }
+
+    if (C0ContainsC1) {
+      // C0's set is a superset of C1's set.
+      // For OR: return LHS (the superset).
+      // For AND: return RHS (the subset).
+      return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+    } else {
+      // C1's set is a superset of C0's set.
+      // For OR: return RHS (the superset).
+      // For AND: return LHS (the subset).
+      return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+    }
+  }
+
   return nullptr;
 }

